// // This module implements a 16-bit synchronous counter that counts down on every positive edge of a clock signal and resets to the maximum value when a reset signal is asserted.
module Counter16Bit (  
    input clk,  
    input reset,  
    input load,  
    input [15:0] load_value,  
    output reg [15:0] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            count <= 16'b0;  
        end else if (load) begin  
            count <= load_value;  
        end else begin  
            count <= count + 1;  
        end  
    end  
endmodule
